import{_ as e,o as a,c as i,ah as t}from"./chunks/framework.C8Zd3T50.js";const k=JSON.parse('{"title":"Local Stack Setup","description":"","frontmatter":{},"headers":[],"relativePath":"dev/local-stack.md","filePath":"dev/local-stack.md"}'),n={name:"dev/local-stack.md"};function l(o,s,h,p,r,d){return a(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="local-stack-setup" tabindex="-1">Local Stack Setup <a class="header-anchor" href="#local-stack-setup" aria-label="Permalink to &quot;Local Stack Setup&quot;">​</a></h1><p>This page covers running the channel and storage servers locally via wrangler so you can develop against them without touching 384.dev.</p><div class="tip custom-block"><p class="custom-block-title">When to use this</p><p>You&#39;re working on lib384 or the server code and need a local target for regression tests. If you just want to build apps using 384.dev infrastructure, skip this — no local server needed.</p></div><hr><h2 id="one-time-setup" tabindex="-1">One-time setup <a class="header-anchor" href="#one-time-setup" aria-label="Permalink to &quot;One-time setup&quot;">​</a></h2><p>The steps in this section only need to be done once per machine (or when you blow away your wrangler state).</p><details class="details custom-block"><summary>Prerequisites</summary><p>See <a href="./prerequisites.html">Prerequisites</a> for install instructions. You&#39;ll need:</p><ul><li><strong>Deno 2.x</strong> — runs lib384, CLI, and test tooling</li><li><strong>Node.js + wrangler</strong> — wrangler runs the Cloudflare Workers locally</li></ul></details><details class="details custom-block"><summary>Local storage paths</summary><p>Both workers persist KV state to a directory outside the project tree so that wrangler data doesn&#39;t land inside your backup boundary. By default this is <code>/Volumes/os384/wrangler</code> (macOS). See <a href="./../local-storage.html">Local storage paths</a> for the full setup, including how to override with <code>OS384_WRANGLER_STATE</code> and the Linux equivalent.</p><p>If you haven&#39;t done this one-time setup yet, do it before proceeding.</p></details><details class="details custom-block"><summary>wrangler.toml</summary><p>The <code>wrangler.toml</code> files contain your Cloudflare <code>account_id</code> and are gitignored. Copy <code>wrangler.template.toml</code> to <code>wrangler.toml</code> in both <code>services/channel/</code> and <code>services/storage/</code> and fill in the account ID. For purely local dev the value doesn&#39;t matter — wrangler only reads it for remote deployments.</p></details><details class="details custom-block"><summary>Seeding a storage token</summary><p>The storage server requires a valid storage token before it will accept writes. Tokens are <a href="#base62">base62</a>-encoded identifiers tracked in the LEDGER_NAMESPACE KV store. This is a one-time <a href="./../../glossary.html#bootstrap">bootstrap</a> step.</p><p>For local development, a well-known shared dev token is used — the same one the Docker admin service seeds automatically. Seed it manually via wrangler&#39;s KV CLI (run from <code>services/storage/</code>):</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/os384/services/storage</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wrangler</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> key</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> put</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --binding=LEDGER_NAMESPACE</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --preview</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --local</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --persist-to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$OS384_WRANGLER_STATE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;LM2r39oAn1F8aMsicKTInXZb5L81JihNghBfJguAPVWZq5k&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &#39;{&quot;hash&quot;:&quot;LM2r39oAn1F8aMsicKTInXZb5L81JihNghBfJguAPVWZq5k&quot;,&quot;used&quot;:false,&quot;size&quot;:1099511627776,&quot;motherChannel&quot;:&quot;&lt;dev&gt;&quot;}&#39;</span></span></code></pre></div><p><code>OS384_WRANGLER_STATE</code> defaults to <code>/Volumes/os384/wrangler</code> if not set. The budget size (1 TB) is effectively unlimited for local dev purposes.</p><div class="info custom-block"><p class="custom-block-title">Why <code>--preview false</code>?</p><p><code>wrangler.toml</code> defines each KV namespace with both an <code>id</code> and a <code>preview_id</code>. Wrangler defaults to the preview namespace, so without <code>--preview false</code> you&#39;ll get an error asking you to specify which one you mean. For local dev we always want the non-preview (<code>id</code>) namespace — the same one the storage worker reads at runtime.</p></div></details><div class="tip custom-block"><p class="custom-block-title">Docker users</p><p>If you&#39;re running the Docker stack instead (<code>services/docker</code>), the admin service handles this automatically:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:3849/refresh</span></span></code></pre></div><p>The same token hash is used in both paths.</p></div><p>:::</p><details class="details custom-block"><summary>Creating a budget channel</summary><p>Once the storage token is seeded and the servers are running, consume the token to create your local <a href="./../../glossary.html#budget-channel">budget channel</a>. The <code>04.01</code> regression test does this for you:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/os384/lib384</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OS384_ENV</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">local</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> deno</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> task</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:04.01</span></span></code></pre></div><p>This calls <code>SB.create(token)</code> with the canonical dev token, creates a channel on your local stack, and saves the resulting <a href="./../../glossary.html#channel-handle">channel handle</a> to <code>.local.data.json</code>. You only need to do this once — subsequent test runs reuse the saved handle.</p><p>The test also stores the budget key in <code>.local.data.json</code> under the channel server URL key. You can inspect it:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/os384/lib384/.local.data.json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> deno</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eval</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  const d = JSON.parse(await Deno.stdin.readText())</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  console.log(JSON.stringify(d, null, 2))</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div></details><details class="details custom-block"><summary>Populating env.js (for browser/app development)</summary><p><code>env.js</code> bridges your local keys into browser and legacy Deno contexts. If you only run CLI tools and tests (which read env vars directly), you can skip this step.</p><p>Copy the template:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/os384/lib384/env.example.js</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/os384/lib384/env.js</span></span></code></pre></div><p>Then edit <code>env.js</code> and fill in the values from <code>.local.data.json</code>:</p><ul><li><code>localBudgetKey</code> — the private key of your local budget channel</li><li><code>localWalletHandle</code> — the channel handle JSON (stringified)</li><li><code>localLedgerKey</code> — the private key of your local ledger channel (if created)</li><li><code>configServerType</code> — set to <code>&#39;local&#39;</code></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><code>env.js</code> contains private key material. It is gitignored — never commit it. Never copy values from a populated <code>env.js</code> into any tracked file.</p></div></details><p>:::</p><hr><h2 id="daily-development" tabindex="-1">Daily development <a class="header-anchor" href="#daily-development" aria-label="Permalink to &quot;Daily development&quot;">​</a></h2><h3 id="starting-the-servers" tabindex="-1">Starting the servers <a class="header-anchor" href="#starting-the-servers" aria-label="Permalink to &quot;Starting the servers&quot;">​</a></h3><p>Open two terminal windows from <code>~/os384/services/</code>.</p><p><strong>Terminal 1 — storage server</strong> (start this one first)</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/os384/services</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev-storage</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Runs on http://localhost:3843</span></span></code></pre></div><p><strong>Terminal 2 — channel server</strong></p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/os384/services</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev-channel</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Runs on http://localhost:3845</span></span></code></pre></div><p>Both workers share the same wrangler state directory via <code>--persist-to</code>, so channel can see the LEDGER_NAMESPACE that storage writes to. No symlink is needed.</p><h3 id="running-tests" tabindex="-1">Running tests <a class="header-anchor" href="#running-tests" aria-label="Permalink to &quot;Running tests&quot;">​</a></h3><p>The <code>lib384/Makefile</code> auto-detects running local servers by probing both ports and sets <code>OS384_ENV=local</code> automatically. So if your servers are up, <code>make test</code> just works:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/os384/lib384</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div><p>To set it manually:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OS384_ENV</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">local</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deno</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> task</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:fast</span></span></code></pre></div><h3 id="verifying-the-stack" tabindex="-1">Verifying the stack <a class="header-anchor" href="#verifying-the-stack" aria-label="Permalink to &quot;Verifying the stack&quot;">​</a></h3><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Confirm the channel server is up</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:3845/api/v2/info</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run the fast test suite</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/os384/lib384</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-fast</span></span></code></pre></div><p>The fast suite includes pure crypto tests (no server needed) plus <code>[fast][channel]</code>, <code>[fast][storage]</code>, and <code>[fast][pages]</code> tests that exercise the local stack. All should pass. See <a href="./regression-tests.html">Regression Tests</a> for the full breakdown.</p><hr><h2 id="app-development-shadow-manifest" tabindex="-1">App development (shadow manifest) <a class="header-anchor" href="#app-development-shadow-manifest" aria-label="Permalink to &quot;App development (shadow manifest)&quot;">​</a></h2><p>When developing an os384 app locally — without the <a href="./../../glossary.html#loader">Loader</a> infrastructure or a deployed service worker — you can use a <a href="./../../glossary.html#shadow-manifest">shadow manifest</a>.</p><p>Create <code>.384.manifest.json</code> (note the leading dot) in your app&#39;s working directory. <a href="./../../glossary.html#appmain">AppMain</a> checks for this dotfile first and uses it in place of <code>384.manifest.json</code> when found. This lets you point the app at your local wrangler stack and iterate without redeploying anything.</p><p>A minimal shadow manifest looks like:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;channelServer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://localhost:3845&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;storageServer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://localhost:3843&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;entry&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;index.html&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>.384.manifest.json</code> should be gitignored — it&#39;s a local dev artifact. Add it to your project&#39;s <code>.gitignore</code>.</p></div><p>To serve the manifest (and your app files) locally without the Loader&#39;s service worker, you can use any static file server. A simple Deno one-liner works:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deno</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-net</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allow-read</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &#39;https://deno.land/std/http/file_server.ts&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3840</span></span></code></pre></div><p>The app will run at <code>http://localhost:3840</code> and <code>AppMain.init()</code> will pick up the shadow manifest automatically.</p>`,42)])])}const g=e(n,[["render",l]]);export{k as __pageData,g as default};
